const { spawnSync } = require('child_process');

exports.runTests = (assert) => {
    // 1. Test ENV
    process.env.SAFE_VAR = 'ok';
    assert.strictEqual(process.env.SAFE_VAR, 'ok');

    try {
        process.env.DANGER_VAR = 'fail';
    } catch (e) {
        assert.strictEqual(e.code, 'EACCES');
    }

    // 2. Test PROC
    // Use absolute paths available in Termux
    const whoamiPath = '/data/data/com.termux/files/usr/bin/whoami';
    const idPath = '/data/data/com.termux/files/usr/bin/id';

    const okRes = spawnSync(whoamiPath);
    assert.strictEqual(okRes.status, 0);

    const failRes = spawnSync(idPath);
    // On EACCES from our hook, spawnSync returns an error
    assert.strictEqual(failRes.status, null);
    assert.strictEqual(failRes.error.code, 'EACCES');
};
